import{m as e,aU as t,z as s,M as a}from"./chunks/framework.LN92DB6A.js";const i=JSON.parse('{"title":"CLAUDE.md","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://guangzhou.suporka.site/CLAUDE"}]]},"headers":[],"relativePath":"CLAUDE.md","filePath":"CLAUDE.md","lastUpdated":1779868425000}');const o=e({name:"CLAUDE.md"},[["render",function(e,i,o,n,l,r){return t(),s("div",null,[...i[0]||(i[0]=[a('<h1 id="claude-md" tabindex="-1">CLAUDE.md <a class="header-anchor" href="#claude-md" aria-label="Permalink to &quot;CLAUDE.md&quot;">​</a></h1><p>This file provides guidance to Claude Code (claude.ai/code) when working with code in this repository.</p><h2 id="project-overview" tabindex="-1">Project Overview <a class="header-anchor" href="#project-overview" aria-label="Permalink to &quot;Project Overview&quot;">​</a></h2><p>A VitePress-based blog site (&quot;广州百晓生&quot;) using the Curve theme — a custom Vue 3 theme for VitePress focused on local lifestyle content (Guangzhou food,探店, city observations). Static site deployed on Vercel + GitHub Pages.</p><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><ul><li><strong>Framework</strong>: VitePress 1.5 (static site generator) + Vue 3 + Vite 5</li><li><strong>State</strong>: Pinia with persisted state plugin</li><li><strong>Styling</strong>: SCSS (via sass package)</li><li><strong>Search</strong>: Algolia (via vue-instantsearch + instantsearch.js)</li><li><strong>Music Player</strong>: APlayer</li><li><strong>Build</strong>: Terser for minification</li></ul><h2 id="key-scripts" tabindex="-1">Key Scripts <a class="header-anchor" href="#key-scripts" aria-label="Permalink to &quot;Key Scripts&quot;">​</a></h2><div class="table-container"><table><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>npm run dev</code></td><td>Start dev server (port 9877 via vite config, <code>--host</code> for LAN)</td></tr><tr><td><code>npm run build</code></td><td>Build for production (output to <code>.vitepress/dist</code>)</td></tr><tr><td><code>npm run preview</code></td><td>Preview production build</td></tr><tr><td><code>npm run lint</code></td><td>ESLint check (.js,.vue,.ts files)</td></tr><tr><td><code>npm run format</code></td><td>Prettier auto-format entire project</td></tr><tr><td><code>npm run deploy:vercel</code></td><td>Deploy to Vercel via CLI</td></tr></tbody></table></div><h2 id="code-quality" tabindex="-1">Code Quality <a class="header-anchor" href="#code-quality" aria-label="Permalink to &quot;Code Quality&quot;">​</a></h2><div class="table-container"><table><thead><tr><th>Config</th><th>Key Rules</th></tr></thead><tbody><tr><td><strong>Prettier</strong> (<code>.prettierrc.json</code>)</td><td>double quotes, trailing commas, tabWidth 2, semi, printWidth 100</td></tr><tr><td><strong>ESLint</strong> (<code>.eslintrc.js</code>)</td><td>airbnb-base + vue/vue3-essential, double quotes, no console restrictions</td></tr></tbody></table></div><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><h3 id="content-structure" tabindex="-1">Content Structure <a class="header-anchor" href="#content-structure" aria-label="Permalink to &quot;Content Structure&quot;">​</a></h3><ul><li><code>posts/YYYY/MMDD.md</code> — Blog posts. File path = URL path (e.g. <code>posts/2024/1010.md</code> → <code>/posts/2024/1010</code>). Frontmatter supports: <code>title</code>, <code>tags</code>, <code>categories</code>, <code>date</code>, <code>description</code>, <code>articleGPT</code>, <code>references</code>, <code>cover</code>, <code>pin</code>.</li><li><code>pages/*.md</code> — Static pages (about, archives, categories, tags, link, project, privacy, cc).</li><li><code>pages/categories/[name].md</code> + <code>[name].paths.mjs</code> — Dynamic category pages.</li><li><code>pages/tags/[name].md</code> + <code>[name].paths.mjs</code> — Dynamic tag pages.</li><li><code>page/[num].md</code> + <code>[num].paths.mjs</code> — Home pagination (page/1, page/2, etc.).</li></ul><h3 id="theme-structure-vitepress-theme" tabindex="-1">Theme Structure (<code>.vitepress/theme/</code>) <a class="header-anchor" href="#theme-structure-vitepress-theme" aria-label="Permalink to &quot;Theme Structure (`.vitepress/theme/`)&quot;">​</a></h3><ul><li><code>App.vue</code> — Root component with layout orchestrator (detects home/post/page routes)</li><li><code>components/</code> — Reusable Vue components (Nav, Footer, Player, Search, Settings, etc.)</li><li><code>views/</code> — Page-level views: Home.vue, Page.vue (static pages), About.vue, Archives.vue, CatOrTag.vue, etc.</li><li><code>store/index.js</code> — Pinia store for global state (theme, scroll, player, settings, background)</li><li><code>utils/</code> — Utilities: post data aggregation, RSS generation, Markdown extensions, Fancybox init, comment init</li><li><code>style/</code> — SCSS files (main, post, animation, font)</li><li><code>assets/themeConfig.mjs</code> — Default theme configuration</li><li><strong><code>@</code> alias</strong> maps to <code>.vitepress/theme</code> (used in Vue imports like <code>@/store</code>)</li></ul><h3 id="build-time-data-flow" tabindex="-1">Build-Time Data Flow <a class="header-anchor" href="#build-time-data-flow" aria-label="Permalink to &quot;Build-Time Data Flow&quot;">​</a></h3><ol><li><code>config.mjs</code> calls <code>getAllPosts()</code> at import time to scan <code>posts/</code> directory</li><li>Each post&#39;s frontmatter is parsed via <code>gray-matter</code>, producing <code>postData[]</code> with id, title, date, tags, categories, description, cover</li><li><code>getAllType()</code>, <code>getAllCategories()</code>, <code>getAllArchives()</code> compute tag/category/archive index from <code>postData</code></li><li>All computed data is injected into <code>themeConfig</code> → available via <code>useData()</code> in Vue components</li><li>At <code>buildEnd</code>, RSS (<code>/rss.xml</code>) and search index (<code>/search-index.json</code>) are generated</li></ol><h3 id="markdown-extensions" tabindex="-1">Markdown Extensions <a class="header-anchor" href="#markdown-extensions" aria-label="Permalink to &quot;Markdown Extensions&quot;">​</a></h3><p>Configured in <code>.vitepress/theme/utils/markdownConfig.mjs</code>:</p><ul><li><code>markdown-it-attrs</code> — custom attributes on elements</li><li><code>markdown-it-container</code> — custom containers (tips, warnings, etc.)</li><li><code>markdown-it-mathjax3</code> — LaTeX math rendering</li><li><code>vitepress-plugin-tabs</code> — tabbed content blocks</li></ul><h3 id="pwa" tabindex="-1">PWA <a class="header-anchor" href="#pwa" aria-label="Permalink to &quot;PWA&quot;">​</a></h3><p>The site uses <code>@vite-pwa/vitepress</code> with service worker caching:</p><ul><li>Fonts/CSS: CacheFirst (<code>file-cache</code>)</li><li>Images (webp/png/jpg): CacheFirst (<code>image-cache</code>)</li><li>IconFont CDN: CacheFirst with 2-day expiry</li><li>Auto-update registration, self-destroying on update</li><li>Fallback excludes: sitemap.xml, rss.xml, robots.txt</li></ul><h3 id="auto-imports" tabindex="-1">Auto-Imports <a class="header-anchor" href="#auto-imports" aria-label="Permalink to &quot;Auto-Imports&quot;">​</a></h3><ul><li><code>unplugin-auto-import</code>: auto-imports Vue 3 and VitePress APIs (ref, computed, useData, useRoute, etc.)</li><li><code>unplugin-vue-components</code>: auto-registers components from <code>.vitepress/theme/components/</code> and <code>.vitepress/theme/views/</code></li></ul><h3 id="theme-configuration-system" tabindex="-1">Theme Configuration System <a class="header-anchor" href="#theme-configuration-system" aria-label="Permalink to &quot;Theme Configuration System&quot;">​</a></h3><p>The theme uses a layered config approach:</p><ol><li><strong>Default config</strong>: <code>.vitepress/theme/assets/themeConfig.mjs</code> — ships with the theme</li><li><strong>User override</strong>: <code>themeConfig.mjs</code> at project root — automatically merged via <code>.vitepress/init.mjs</code></li><li><strong>Post data</strong> (tags, categories, archives) is computed at build time from frontmatter</li></ol><h3 id="key-config-areas-in-themeconfig" tabindex="-1">Key Config Areas (in themeConfig) <a class="header-anchor" href="#key-config-areas-in-themeconfig" aria-label="Permalink to &quot;Key Config Areas (in themeConfig)&quot;">​</a></h3><ul><li><code>siteMeta</code> — title, description, logo, author, site URL, language</li><li><code>cover</code> — Two-column layout toggle, default cover images for posts</li><li><code>comment</code> — Artalk or Twikoo integration</li><li><code>aside</code> — Sidebar widgets (hello text, TOC, tags, countdown, site stats)</li><li><code>music</code> — APlayer playlist configuration</li><li><code>search</code> — Algolia app ID and API key</li><li><code>fancybox</code> — Image lightbox</li><li><code>jumpRedirect</code> — External link redirect confirmation</li><li><code>nav</code> and <code>navMore</code> — Navigation menu structure</li><li><code>footer</code> — Social links and sitemap</li></ul><h3 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h3><ul><li><strong>Vercel</strong>: Primary, configured via <code>vercel.json</code> (framework: vitepress, SPA rewrites)</li><li><strong>GitHub Pages</strong>: <code>.github/workflows/deploy.yml</code> — builds on push to master, deploys to <code>gh-pages</code> branch</li><li>Post data (RSS) is generated in <code>buildEnd</code> hook</li></ul><h2 id="post-frontmatter" tabindex="-1">Post Frontmatter <a class="header-anchor" href="#post-frontmatter" aria-label="Permalink to &quot;Post Frontmatter&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Post Title</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Tag1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Tag2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">categories</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">CategoryName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">date</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2024-10-10</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SEO description</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">articleGPT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">AI summary for sidebar widget</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">cover</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://example.com/cover.jpg</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">pin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # pin to top</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">references</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Reference Name</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://example.com</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="agent-工作流-当日热门选题" tabindex="-1">Agent 工作流：当日热门选题 <a class="header-anchor" href="#agent-工作流-当日热门选题" aria-label="Permalink to &quot;Agent 工作流：当日热门选题&quot;">​</a></h2><p>项目内置了一个三步走选题 agent，位于 <code>plan/agent/</code> 目录：</p><ol><li><strong>搜热题</strong> → <code>plan/agent/step-1-hot-topics.md</code> — 从微博/小红书/大众点评/广州日报搜索当日热门</li><li><strong>挖素材</strong> → <code>plan/agent/step-2-sources.md</code> — 对每个选题深度挖掘热门文章素材</li><li><strong>合成稿</strong> → <code>plan/agent/step-3-drafts.md</code> — 按风格要求合成候选文章</li></ol><p>使用方式：引用对应 prompt 文件的内容执行。产物存入 <code>plan/hot-topics/</code>、<code>plan/sources/</code>、<code>plan/drafts/</code>。</p><h2 id="知乎文章爬取" tabindex="-1">知乎文章爬取 <a class="header-anchor" href="#知乎文章爬取" aria-label="Permalink to &quot;知乎文章爬取&quot;">​</a></h2><p>使用 <code>/scrape-zhihu</code> slash command 可一键将知乎专栏文章转为本博客 Markdown 文章。</p><p><strong>基础用法：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/scrape-zhihu https://zhuanlan.zhihu.com/p/xxxxxx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>完整参数：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/scrape-zhihu &lt;url&gt; [--slug &lt;slug&gt;] [--date &lt;YYYY-MM-DD&gt;] [--tags &lt;tag1,tag2&gt;] [--categories &lt;cat&gt;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>产物：</strong></p><ul><li>Markdown 文章：<code>posts/&lt;year&gt;/&lt;slug&gt;.md</code>（含 frontmatter）</li><li>WebP 图片：<code>public/images/&lt;slug&gt;-01.webp</code> … <code>&lt;slug&gt;-NN.webp</code></li></ul><p><strong>脚本文件：</strong></p><ul><li><code>scripts/scrape_zhihu.py</code> — 主流程（Python，<code>pip install requests Pillow</code>）</li><li><code>scripts/_zhihu_renderer.mjs</code> — Puppeteer 渲染器（Node.js，需系统 Chrome/Edge）</li></ul><h2 id="小红书笔记爬取" tabindex="-1">小红书笔记爬取 <a class="header-anchor" href="#小红书笔记爬取" aria-label="Permalink to &quot;小红书笔记爬取&quot;">​</a></h2><p>使用 <code>/scrape-xiaohongshu</code> slash command 可一键将小红书笔记转为本博客 Markdown 文章。</p><p><strong>基础用法：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/scrape-xiaohongshu https://www.xiaohongshu.com/explore/xxxxxx?xsec_token=...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>完整参数：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/scrape-xiaohongshu &lt;url&gt; [--slug &lt;slug&gt;] [--date &lt;YYYY-MM-DD&gt;] [--tags &lt;tag1,tag2&gt;] [--categories &lt;cat&gt;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>产物：</strong></p><ul><li>Markdown 文章：<code>posts/&lt;year&gt;/&lt;slug&gt;.md</code>（含 frontmatter，笔记 #标签 自动合并）</li><li>WebP 图片：<code>public/images/&lt;slug&gt;-01.webp</code> … <code>&lt;slug&gt;-NN.webp</code></li></ul><p><strong>脚本文件：</strong></p><ul><li><code>scripts/scrape_xiaohongshu.py</code> — 主流程（Python，<code>pip install requests Pillow</code>）</li><li><code>scripts/_xiaohongshu_renderer.mjs</code> — Puppeteer 渲染器（Node.js，移动端 UA 免登录）</li></ul><h2 id="微信公众号文章爬取" tabindex="-1">微信公众号文章爬取 <a class="header-anchor" href="#微信公众号文章爬取" aria-label="Permalink to &quot;微信公众号文章爬取&quot;">​</a></h2><p>使用 <code>/scrape-wechat</code> slash command 可将微信公众号文章转为本博客 Markdown 文章。</p><p><strong>基础用法：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/scrape-wechat &lt;url&gt; [--slug &lt;slug&gt;] [--date &lt;YYYY-MM-DD&gt;] [--tags &lt;tag1,tag2&gt;] [--categories &lt;cat&gt;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>脚本文件：</strong></p><ul><li><code>scripts/scrape_wechat.py</code> — 主流程（Python，<code>pip install requests Pillow</code>）</li><li><code>scripts/_wechat_renderer.mjs</code> — Puppeteer 渲染器（Node.js）</li></ul>',64)])])}]]);export{i as __pageData,o as default};
